/**
 * Chain Staleness Checker — PostToolUse hook (M168 Phase 3, #1913)
 *
 * Layer 3 of the 4-layer coordination architecture. Watches the
 * project-local chain state file (`.claude/chain/state.json`) for
 * activity. If the chain hasn't been updated in more than
 * STALE_THRESHOLD_MS AND its status isn't 'completed', emits a single
 * `chain_stale` event into the cross-session event log so other
 * sessions / monitors can react.
 *
 * Rate-limited to once per RATE_LIMIT_MS per session — a hot tool-use
 * loop touches the chain file at most once every five minutes per sid.
 *
 * Hook event: PostToolUse (async, timeout: 3s, matcher: catchall).
 */

import { existsSync, readFileSync, statSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { appendEvent } from '../lib/event-log.js';
import { createHash } from 'node:crypto';

const HOOK_NAME = 'posttool/chain-staleness-checker';

/** 30 minutes. */
const STALE_THRESHOLD_MS = 30 * 60 * 1000;
/** 5 minutes — per-session check frequency. */
const RATE_LIMIT_MS = 5 * 60 * 1000;

const CHAIN_STATE_REL = join('.claude', 'chain', 'state.json');

interface ChainState {
  chain_id?: string;
  phase?: string;
  status?: string;
  updated_at?: string | number;
}

// Module-level rate-limit cache: last check timestamp (ms) per sid.
const lastCheck = new Map<string, number>();

function hashRepo(repoPath: string): string {
  return createHash('sha256').update(repoPath).digest('hex').slice(0, 12);
}

/** Parse updated_at as ms-since-epoch. Accepts ISO strings or numbers. */
function parseUpdatedAt(raw: unknown): number | null {
  if (typeof raw === 'number' && Number.isFinite(raw)) return raw;
  if (typeof raw === 'string') {
    const parsed = Date.parse(raw);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

export function chainStalenessChecker(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sid = input.session_id;
  if (!sid) return outputSilentSuccess();

  const nowMs = Date.now();
  const prev = lastCheck.get(sid) ?? 0;
  if (nowMs - prev < RATE_LIMIT_MS) {
    return outputSilentSuccess();
  }
  lastCheck.set(sid, nowMs);

  const projectDir = ctx.projectDir;
  if (!projectDir) return outputSilentSuccess();

  const statePath = join(projectDir, CHAIN_STATE_REL);
  if (!existsSync(statePath)) return outputSilentSuccess();

  let state: ChainState;
  try {
    state = JSON.parse(readFileSync(statePath, 'utf8')) as ChainState;
  } catch (err) {
    ctx.log(HOOK_NAME, `parse failed: ${(err as Error).message}`, 'warn');
    return outputSilentSuccess();
  }

  if (state.status === 'completed') return outputSilentSuccess();

  // Prefer JSON-declared updated_at, fall back to file mtime.
  let updatedAtMs = parseUpdatedAt(state.updated_at);
  if (updatedAtMs == null) {
    try {
      updatedAtMs = statSync(statePath).mtimeMs;
    } catch {
      return outputSilentSuccess();
    }
  }

  const ageMs = nowMs - updatedAtMs;
  if (ageMs < STALE_THRESHOLD_MS) return outputSilentSuccess();

  try {
    appendEvent({
      type: 'chain_stale',
      ts: nowMs,
      repo_hash: hashRepo(projectDir),
      sid,
      chain_id: typeof state.chain_id === 'string' ? state.chain_id : undefined,
      phase: typeof state.phase === 'string' ? state.phase : undefined,
      stale_for_ms: ageMs,
    });
    ctx.log(HOOK_NAME, `chain_stale emitted: age=${Math.floor(ageMs / 1000)}s`);
  } catch (err) {
    ctx.log(HOOK_NAME, `append failed: ${(err as Error).message}`, 'warn');
  }

  return outputSilentSuccess();
}

/** Exposed for tests. */
export const __internals = {
  lastCheck,
  STALE_THRESHOLD_MS,
  RATE_LIMIT_MS,
  CHAIN_STATE_REL,
};
